/**
 * Represents a chat completion response returned by model, based on the provided input.
 */
export const zCreateChatCompletionResponse = z.object({
  id: z.string(),
  choices: z.array(
    z.object({
      finish_reason: z.enum([
        'stop',
        'length',
        'tool_calls',
        'content_filter',
        'function_call',
      ]),
      index: z.int(),
      message: zChatCompletionResponseMessage,
      logprobs: z.union([
        z.object({
          content: z.union([z.array(zChatCompletionTokenLogprob), z.unknown()]),
          refusal: z.union([z.array(zChatCompletionTokenLogprob), z.unknown()]),
        }),
        z.unknown(),
      ]),
    }),
  ),
  created: z.int(),
  model: z.string(),
  service_tier: zServiceTier.optional(),
  system_fingerprint: z.string().optional(),
  object: z.enum(['chat.completion']),
  usage: zCompletionUsage.optional(),
})

/**
 * Represents a streamed chunk of a chat completion response returned
 * by the model, based on the provided input.
 * [Learn more](/docs/guides/streaming-responses).
 *
 */
export const zCreateChatCompletionStreamResponse = z.object({
  id: z.string(),
  choices: z.array(
    z.object({
      delta: zChatCompletionStreamResponseDelta,
      logprobs: z
        .object({
          content: z.array(zChatCompletionTokenLogprob).nullable(),
          refusal: z.array(zChatCompletionTokenLogprob).nullable(),
        })
        .nullish(),
      finish_reason: z.enum([
        'stop',
        'length',
        'tool_calls',
        'content_filter',
        'function_call',
      ]),
      index: z.int(),
    }),
  ),
  created: z.int(),
  model: z.string(),
  service_tier: zServiceTier.optional(),
  system_fingerprint: z.string().optional(),
  object: z.enum(['chat.completion.chunk']),
  usage: zCompletionUsage.optional(),
})

export const zModelResponseProperties = z.object({
  metadata: zMetadata.optional(),
  top_logprobs: z.union([z.int().gte(0).lte(20), z.unknown()]).optional(),
  temperature: z.union([z.number().gte(0).lte(2), z.unknown()]).optional(),
  top_p: z.union([z.number().gte(0).lte(1), z.unknown()]).optional(),
  user: z.string().optional(),
  safety_identifier: z.string().max(64).optional(),
  prompt_cache_key: z.string().optional(),
  service_tier: zServiceTier.optional(),
  prompt_cache_retention: z
    .union([z.enum(['in_memory', '24h']), z.unknown()])
    .optional(),
})

export const zCreateModelResponseProperties = zModelResponseProperties.and(
  z.object({
    top_logprobs: z.int().gte(0).lte(20).optional(),
  }),
)

export const zServiceTierEnum = z.enum(['auto', 'default', 'flex', 'priority'])

export const zSkillReferenceParam = z.object({
  type: z.enum(['skill_reference']).default('skill_reference'),
  skill_id: z.string().min(1).max(64),
  version: z.string().optional(),
})

export const zContainerAutoParam = z.object({
  type: z.enum(['container_auto']).default('container_auto'),
  file_ids: z.array(z.string()).max(50).optional(),
  memory_limit: z.union([zContainerMemoryLimit, z.unknown()]).optional(),
  network_policy: z
    .discriminatedUnion('type', [
      zContainerNetworkPolicyDisabledParam,
      zContainerNetworkPolicyAllowlistParam,
    ])
    .optional(),
  skills: z
    .array(
      z.union([
        z
          .object({
            type: z.literal('SkillReferenceParam'),
          })
          .and(zSkillReferenceParam),
        z
          .object({
            type: z.literal('InlineSkillParam'),
          })
          .and(zInlineSkillParam),
      ]),
    )
    .max(200)
    .optional(),
})

